const MAX = 5;
const used = new Set();

// Directly pull data from 'Get row(s)1' regardless of the path taken
const inventoryRows = $("get rows").all();

for (const item of inventoryRows) {
  const raw = item.json.box;
  if (!raw) continue;

  const b = Number(raw);
  if (Number.isInteger(b) && b >= 1 && b <= MAX) {
    used.add(b);
  }
}

// Compute free boxes
const free = [];
for (let i = 1; i <= MAX; i++) {
  if (!used.has(i)) free.push(i);
}

return {
  used_boxes: Array.from(used),
  free_boxes: free,
  selected_box: free.length > 0 ? free[0] : null
};

const items = $input.all();

let medicine = null;
let freeBoxes = [];

for (const item of items) {
  if (item.json && item.json.medicine) {
    medicine = item.json.medicine;
  }
  if (item.json && Array.isArray(item.json.free_boxes)) {
    freeBoxes = item.json.free_boxes;
  }
}

if (!Array.isArray(freeBoxes)) {
  freeBoxes = [];
}

return [{
  json: {
    medicine: medicine || "Unknown",
    free_boxes: freeBoxes,
    message: freeBoxes.length
      ? `I detected this as ${medicine}. Available boxes: ${freeBoxes.join(", ")}`
      : `I detected this as ${medicine}. No boxes available.`
  }
}];

