const raw = $json.output || $json.text || "";

const cleaned = raw
  .replace(/```json/gi, "")
  .replace(/```/g, "")
  .trim();

let medicine = "unknown";

try {
  const parsed = JSON.parse(cleaned);
  medicine = parsed.medicine || "unknown";
} catch (e) {
  if (cleaned.length > 0) medicine = cleaned;
}

// Convert box to number
const box = Number($('Edit Fields3').first().json.body.box);

return [{
  json: {
    box,
    medicine
  }
}];

const rows = $input.all();

return rows.map(r => {

  let raw = r.json.time;
  let times = [];

  if (raw) {

    raw = String(raw);

    // remove leading =
    raw = raw.replace(/^=/, "");

    // remove surrounding quotes
    raw = raw.replace(/^"+|"+$/g, "");

    // remove escaped quotes
    raw = raw.replace(/\\"/g, '"');

    // if array exists inside text
    const match = raw.match(/\[.*\]/);

    if (match) {
      try {
        times = JSON.parse(match[0]);
      } catch {
        times = [];
      }
    }

    // single time
    else if (/^\d{2}:\d{2}$/.test(raw)) {
      times = [raw];
    }
  }

  let uid = r.json.rfid_id || "";

  uid = String(uid)
    .replace(/\s+/g,"")
    .replace(/"/g,"")
    .toUpperCase();

  return {
    json: {
      box: Number(r.json.box),
      times,
      uid
    }
  };

});

const raw = $input.first().json;
let uid = "";
if (raw.body && raw.body.uid)       uid = String(raw.body.uid);
else if (raw.uid)                   uid = String(raw.uid);
else if (raw.body && typeof raw.body === "string") {
  try { uid = String(JSON.parse(raw.body).uid || ""); } catch(e) {}
}
return [{ json: { uid: uid.trim() } }];

const all = $input.all();
if (!all || all.length === 0) return [{ json: { uid: "" } }];
const rows = all.map(i => i.json);
rows.sort((a, b) => (Number(b.id) || 0) - (Number(a.id) || 0));
// Row starts as demo_user, gets updated to RFID uid after tap
const tapped = rows.find(r =>
  r.user &&
  String(r.user).trim() !== "" &&
  String(r.user).trim() !== "demo_user"
);
return [{ json: { uid: tapped ? String(tapped.user).trim() : "" } }];
